  cihai: [
    {word: "Ataraxia", def: "心灵宁静——伊壁鸠鲁伦理学的终极目标。", source: "伊壁鸠鲁《致美诺西斯的信》"},
    {word: "Tetrapharmakos", def: "四药方：不惧神、不畏死、善易得、恶可忍。", source: "菲洛德穆残篇"},
    {word: "伊壁鸠鲁学派", def: "古希腊哲学流派，以伊壁鸠鲁为创始人，主张快乐主义、原子论和感觉主义，追求无痛苦（aponia）与心灵宁静（ataraxia）。", source: "《辞海》哲学分册"},
    {word: "快乐主义", def: "伦理学学说，认为快乐是人生最高善和目的，但伊壁鸠鲁强调理性节制，反对纵欲。", source: "《辞海》伦理学卷"},
    {word: "原子论", def: "古希腊唯物主义哲学，认为万物由不可分割的原子与虚空构成，伊壁鸠鲁继承德谟克利特并加入原子偏斜说。", source: "《辞海》哲学分册"},
    {word: "原子偏斜说", def: "伊壁鸠鲁对原子论的修正，认为原子在运动中会自发偏离直线，从而解释自由意志与偶然性。", source: "《辞海》西方哲学史"},
    {word: "准则学", def: "伊壁鸠鲁学派的认识论，以感觉、预想和情感为判断真伪的三准则。", source: "《辞海》哲学分册"},
    {word: "阿塔拉西亚", def: "希腊语ataraxia的音译，意为‘心灵宁静’，是伊壁鸠鲁学派追求的最高精神境界。", source: "《辞海》哲学分册"},
    {word: "阿波尼亚", def: "希腊语aponia的音译，意为‘无痛苦’，是伊壁鸠鲁学派认为身体应达到的理想状态。", source: "《辞海》哲学分册"},
    {word: "伊壁鸠鲁花园", def: "伊壁鸠鲁在雅典创办的学校，位于一座花园中，接纳妇女与奴隶，强调友谊与隐修生活。", source: "《辞海》教育史"},
    {word: "四重疗法", def: "伊壁鸠鲁提出的消除恐惧的方法：神不足惧、死不足忧、善易得、恶易忍。", source: "《辞海》伦理学卷"},
    {word: "卢克莱修", def: "古罗马诗人、哲学家，以长诗《物性论》系统阐述伊壁鸠鲁哲学，对后世唯物主义影响深远。", source: "《辞海》人物卷"},
    {word: "赫库兰尼姆纸莎草文献", def: "18世纪在意大利赫库兰尼姆古城发现的古卷，包含大量伊壁鸠鲁学派著作，尤其是菲洛德穆的作品。", source: "《辞海》考古学"},
    {word: "伊壁鸠鲁悖论", def: "又称‘恶的问题’，由伊壁鸠鲁提出：若神愿除恶却无力，则神非全能；若有能力却不愿，则神非善。", source: "《辞海》宗教哲学"},
  ],
  quotes: [
    {text: "死亡与我们无关。", author: "伊壁鸠鲁", exp: "消除死亡恐惧的经典论证。"},
    {text: "快乐是幸福生活的起点与终点。", author: "伊壁鸠鲁", exp: "强调快乐作为人生的最高目的，但需通过理性选择避免痛苦。"},
    {text: "死亡与我们无关，因为当我们存在时，死亡尚未到来；当死亡到来时，我们已不存在。", author: "伊壁鸠鲁", exp: "消除对死亡的恐惧，认为死后无感知，故无痛苦。"},
    {text: "神并不关心人类事务，因为关心会破坏神的至福状态。", author: "伊壁鸠鲁", exp: "伊壁鸠鲁神学认为神是完美幸福的模型，不干预世界。"},
    {text: "友谊使快乐倍增，使痛苦减半。", author: "梅特罗多罗斯", exp: "强调友谊在伊壁鸠鲁学派中的核心地位，是快乐的重要来源。"},
    {text: "智慧的人不会参与政治，除非发生意外。", author: "伊壁鸠鲁", exp: "主张远离公共生活以保持内心宁静，避免焦虑。"},
    {text: "自然欲望是容易满足的，空虚欲望则永无止境。", author: "菲洛德穆", exp: "区分必要欲望与奢侈欲望，指导人们追求简单生活。"},
    {text: "恐惧源于无知，尤其是对自然现象的无知。", author: "卢克莱修", exp: "在《物性论》中解释，了解原子运动可消除对雷电、地震的恐惧。"},
    {text: "灵魂由原子构成，死亡时原子消散，故无来世惩罚。", author: "卢克莱修", exp: "唯物主义灵魂观，反驳宗教恐吓。"},
    {text: "真正的快乐是身体无痛苦、灵魂无纷扰。", author: "伊壁鸠鲁", exp: "对快乐主义的核心定义，强调静态快乐（aponia + ataraxia）。"},
    {text: "不要因害怕神而放弃快乐，神是冷漠的。", author: "科洛特斯", exp: "批判宗教迷信，鼓励人们追求现世幸福。"},
    {text: "理性是快乐的指南，而非压抑快乐的枷锁。", author: "赫尔马库斯", exp: "强调伊壁鸠鲁的快乐计算法，与禁欲主义划清界限。"},
    {text: "一切感觉都是真实的，错误在于判断。", author: "芝诺（西顿的）", exp: "伊壁鸠鲁认识论的基础，感觉是知识的唯一来源。"},
  ],
