  cihai: [
    {word: "萨满", def: "源自通古斯语'šaman'，意为'知晓者'。在多层宇宙间穿梭、沟通人与灵界的仪式专家，是最古老的精神职业之一。", source: "西伯利亚传统"},
    {word: "三层宇宙", def: "萨满宇宙论的基本框架：上界（天界）、中界（人间界）、下界（冥界），由世界轴连接。", source: "泛萨满传统"},
    {word: "世界轴", def: "连接宇宙三层的象征性轴线，常以世界树、世界山、烟囱或彩虹等形式出现，萨满沿此轴进行灵魂旅程。", source: "比较神话学"},
    {word: "图腾", def: "源自北美奥吉布瓦语，指与某个氏族或个体有特殊精神联系的动物或自然物。图腾关系构成了萨满社会的基本组织原则。", source: "美洲原住民传统"},
    {word: "灵魂失落", def: "萨满病理学核心概念，疾病被理解为灵魂因创伤、恐惧或邪灵侵袭而部分离开身体，治疗即灵魂找回。", source: "泛萨满传统"},
    {word: "形态转换", def: "萨满在灵界旅程中转变为动物形态（熊、狼、鹰等）的能力，不是隐喻而是本体论层面的变形。", source: "西伯利亚萨满传统"},
    {word: "万物有灵论", def: "认为动物、植物、山、河等自然物具有精神或灵魂的哲学观点，萨满哲学的本体论基础。爱德华·泰勒最早系统论述。", source: "人类学传统"},
    {word: "萨满鼓", def: "萨满最核心的仪式工具，有节奏的击鼓是进入恍惚状态的主要手段。鼓本身被视为'灵魂之马'或'灵魂之舟'。", source: "泛萨满传统"},
    {word: "成丁礼", def: "萨满启蒙的仪式过程，通常涉及象征性的死亡、肢解和重生，经历者获得在灵界旅行的能力。", source: "西伯利亚-美洲传统"},
    {word: "守护灵", def: "与特定萨满建立联系并协助其工作的灵性存在，常以动物形态出现（熊灵、狼灵、鹰灵等）。", source: "泛萨满传统"},
    {word: "植物之灵", def: "萨满传统中用以致幻或疗愈的植物被认为具有强大的灵性，使用者需以仪式和敬畏对待。", source: "亚马逊-西伯利亚传统"},
    {word: "汗蒸屋", def: "美洲原住民萨满传统中的净化仪式空间，结合热、蒸汽、祈祷和击鼓来促进精神和身体的疗愈。", source: "北美原住民传统"},
    {word: "灵歌", def: "萨满在仪式中接收或传承的歌谣，每一首都有一个特定的灵性来源和用途，是萨满知识的主要载体。", source: "泛萨满传统"},
    {word: "附体", def: "萨满允许灵性存在暂时进入其身体的过程，不同于'被附身'，附体是萨满主动的、可控的状态。", source: "泛萨满传统"},
    {word: "白色萨满与黑色萨满", def: "西伯利亚传统中对萨满的二分：白色萨满与上界沟通，服务于疗愈和丰产；黑色萨满与下界沟通，在必要时处理死亡和恶灵。", source: "西伯利亚传统"},
    {word: "梦时", def: "澳洲原住民的概念，与萨满意识状态相通，是创世祖先活动的永恒当下，可通过仪式重新进入。", source: "澳洲原住民传统"},
    {word: "精灵婚", def: "萨满与灵界的'婚姻'关系，灵界伴侣成为萨满力量来源和导师。这在许多萨满传统中是被认可的关系形式。", source: "泛萨满传统"},
    {word: "口弦琴", def: "西伯利亚和中亚萨满常用的乐器，其嗡鸣声被认为能模仿自然精灵的语言，是进入意识转变状态的工具。", source: "西伯利亚-中亚传统"},
    {word: "骨卜", def: "将动物骨头（通常为肩胛骨）在火中烧灼以读取裂纹进行占卜的萨满技术，广泛存在于欧亚大陆北部。", source: "北亚传统"},
    {word: "灵视", def: "萨满的核心能力之一，在非寻常意识状态下'看见'灵界存在、疾病根源或未来事件的能力。", source: "泛萨满传统"},
  ],
  quotes: [
    {text: "风是我的父亲，大地是我的母亲，火是我的兄弟，水是我的姐妹。", author: "西伯利亚萨满祷词", exp: "萨满自然哲学的精髓：人与自然的亲属关系。不是主宰自然而是融入自然。"},
    {text: "我死过很多次，所以我活着。", author: "西伯利亚萨满谚语", exp: "萨满成丁礼中象征性死亡与重生的哲学意义——真正的活着需要经历'死亡'。"},
    {text: "动物的眼睛是森林的窗户——看进去，你会看到你自己。", author: "北欧萨米谚语", exp: "人与动物的镜像关系：动物不是他者，而是自性的投射和延伸。"},
    {text: "鼓是马，鼓槌是鞭，萨满骑着鼓奔向天空。", author: "西伯利亚萨满传统", exp: "萨满工具的诗意本体论：击鼓不是音乐表演而是交通工具，是上下宇宙的'载具'。"},
    {text: "一棵树连接着三个世界：根扎入下界，干立于中界，冠伸向上界。", author: "萨满世界轴意象", exp: "宇宙树是三层宇宙的微缩模型——树本身就是宇宙结构。"},
    {text: "疾病是灵魂走失的孩子。", author: "萨满治疗哲学", exp: "重新定义疾病：不是身体的故障而是灵魂的缺席。治疗就是回家。"},
    {text: "不要看着我要看着你。", author: "萨满训练格言", exp: "萨满认识论的悖论：真正的知识不是关于外物的，而是关于自我的——向外看转向向内看。"},
    {text: "我们不是从大地获取，我们是大地在感受自己。", author: "萨满生态哲学", exp: "最彻底的环境哲学：人类是地球自我意识的中介而非奴役者。"},
    {text: "影子很短但灵魂很长。", author: "蒙古萨满谚语", exp: "物质与精神的萨满辩证法：可见的世界只是冰山一角。"},
    {text: "每个动物都知道它的路，只有人类迷路了。", author: "西伯利亚谚语", exp: "对现代性的萨满式批判：进步叙事让我们失去了'本能'的智慧。"},
    {text: "你杀死什么，你就成为什么。", author: "萨满狩猎伦理", exp: "猎人-猎物关系的循环：每一次杀死都是一次转化，一次身份的交换。"},
    {text: "天黑之后，萨满就是所有人的太阳。", author: "西伯利亚萨满传统", exp: "萨满作为社群的'光'：在危机和黑暗中，萨满提供照明和方向。"},
    {text: "身体的疼痛是灵魂的敲门声。", author: "萨满治疗哲学", exp: "身心一体论：身体症状是灵魂失衡的物理显现。"},
    {text: "最大的敌人不在森林里，而在自己心里。", author: "萨满心理学", exp: "萨满传统对'内在敌人'的认知：真正的战斗总是内在的。"},
    {text: "鼓声中，时间弯曲了。", author: "萨满意识研究", exp: "萨满仪式中的时间经验：击鼓的重复节奏改变了意识的时间性。"},
    {text: "杀死一只熊之前，要先成为一只熊。", author: "西伯利亚狩猎仪式", exp: "萨满共情伦理：了解'猎物'的唯一方式是本体论层面的体验。"},
    {text: "烟是灵魂的语言。", author: "美洲原住民传统", exp: "仪式中烟雾的物质性作为沟通灵界的中介——可见的与不可见的在此交汇。"},
    {text: "你的祖先不是逝者，是你的血液里的歌。", author: "蒙古萨满传统", exp: "祖先不是历史记忆而是活着的当下——血统中的存在。"},
    {text: "石头会说话，但你需要用骨头去听。", author: "西伯利亚萨满格言", exp: "萨满认识论：知识的获取需要特殊的感知器官——不是肉体器官而是精神器官。"},
    {text: "雪不脏，脏的是踩过雪的人。", author: "萨哈（雅库特）谚语", exp: "原始自然的纯洁性与人类介入的污染——萨满环境伦理的诗意表达。"},
  ],
