  cihai: [
    {word: "腾格里（Tengri）", def: "蒙古与突厥民族信仰中的至高天神，意为‘永恒蓝天’。代表宇宙秩序、生命之源与道德审判者，是蒙古中亚哲学宇宙论的核心。", source: "《蒙古秘史》"},
    {word: "约孙（Yosun）", def: "蒙古传统习惯法，意为‘道理’或‘规矩’。涵盖社会伦理、部落关系与自然禁忌，是游牧社会不成文的道德与法律基础。", source: "《大札撒》相关研究"},
    {word: "札撒（Yassa）", def: "成吉思汗颁布的成文法典，意为‘法令’。强调团结、忠诚、公正与军事纪律，被视为‘天力’在人间统治的具体体现。", source: "成吉思汗《大札撒》"},
    {word: "博克多（Bogd）", def: "蒙古语意为‘神圣’或‘圣者’，常用于尊称高僧或活佛。在哲学语境中，指代精神与世俗权力的合一者，如博克多汗。", source: "蒙古佛教传统"},
    {word: "转轮王（Chakravartin）", def: "源自印度佛教，蒙古佛教哲学中用以描述理想统治者，即通过佛法与正义统一世界的‘宇宙君主’，如忽必烈被比附为转轮王。", source: "《蒙古源流》"},
    {word: "苏菲（Sufi）", def: "伊斯兰神秘主义派别，在中亚与游牧文化深度结合，强调通过爱、冥想与导师引导直接体验神，代表人物如叶塞维、纳格什班德。", source: "伊斯兰哲学史"},
    {word: "呼图克图（Khutuktu）", def: "蒙古藏传佛教中的高级转世活佛称号，意为‘圣者’。象征智慧与慈悲的连续传承，是蒙古佛教哲学中‘化身’观念的核心。", source: "藏传佛教蒙古体系"},
    {word: "欧亚主义（Eurasianism）", def: "19世纪末至20世纪兴起于俄罗斯与中亚的思想流派，主张欧亚大陆是独特文明，游牧民族（如蒙古）在其中扮演桥梁角色。", source: "当代中亚哲学研究"},
  ],
  quotes: [
    {text: "长生天之下，大地之上，唯有真理与勇气不可战胜。", author: "《蒙古秘史》", exp: "表达了蒙古哲学中‘天’与‘人’的契约：真理（正义）和勇气（行动）是游牧民族生存的最高品质，也是政治合法性的来源。"},
    {text: "不要因路远而踌躇，只要去，必到达。", author: "成吉思汗（传）", exp: "体现了游牧文明对行动与毅力的推崇，将哲学思考落实为实践，反对空谈与犹豫，是‘知行合一’的草原版。"},
    {text: "我的力量来自团结，我的智慧来自倾听。", author: "成吉思汗（《箴言》）", exp: "强调集体主义与包容性，统治者的智慧不在于独断，而在于融合不同部落、宗教与文化的意见，这是蒙古帝国成功的精神基础。"},
    {text: "心若慈悲，剑亦慈悲；心若暴虐，经亦暴虐。", author: "八思巴（《彰所知论》）", exp: "反映了蒙古佛教哲学对‘心’的重视：任何外在行为（包括战争与宗教）的善恶取决于内在动机，是佛教伦理与游牧尚武精神的调和。"},
    {text: "草原不是我们的财产，而是我们从子孙那里借来的。", author: "蒙古谚语（传统游牧伦理）", exp: "体现了蒙古中亚哲学中的生态智慧：人类是自然的守护者而非所有者，代际责任与可持续性高于短期利益，与当代环保主义高度契合。"},
    {text: "真主是唯一的，但通往他的路如沙漠中的沙粒一样多。", author: "阿合马·叶塞维（《智慧集》）", exp: "表达了中亚苏菲主义的包容性：在伊斯兰框架下承认多元精神路径，与游牧民族尊重不同宗教的传统一致，是跨文化哲学对话的典范。"},
    {text: "完美的城邦如同健康的身体，各部分和谐运作，才能抵御疾病。", author: "法拉比（《美德城邦居民意见书》）", exp: "法拉比虽生于中亚，但其哲学融合了柏拉图与伊斯兰思想，此句强调社会有机体论，影响了后来中亚与蒙古的政治哲学中对‘和谐’的追求。"},
    {text: "存在不是事物，而是每一刻的创造。", author: "伊本·西那（《治疗论》）", exp: "伊本·西那的形而上学对存在本质的探讨，深刻影响了中亚伊斯兰哲学，其‘创造性存在’观念与游牧民族对流动、变化的敏感相呼应。"},
    {text: "过去不是死去的沙丘，而是活着的根。", author: "仁钦·乔玛（《游牧文明论》）", exp: "当代蒙古哲学家的反思：传统不是博物馆中的陈列品，而是塑造现代性的活水源泉，呼吁从游牧智慧中寻找解决现代问题的钥匙。"},
    {text: "在草原上，没有陌生人，只有尚未认识的兄弟。", author: "哈萨克谚语（中亚游牧伦理）", exp: "体现了游牧文明中‘ hospitality’（好客）的哲学基础：将他人纳入自己的伦理圈，打破封闭与敌视，是跨民族、跨宗教交流的道德前提。"},
  ],
  works: [
    {title: "《蒙古秘史》", author: "不详（蒙古宫廷史官）", era: "1240年", desc: "蒙古族最早的史诗性编年史，以文学与哲学语言记录了成吉思汗的祖先、崛起与统一过程，核心观念包括‘天力’、‘命运’与‘团结’，是研究蒙古宇宙论与政治伦理的基石。"},
    {title: "《大札撒》（残篇）", author: "成吉思汗", era: "1206年", desc: "成吉思汗颁布的法典，现存片段散见于波斯与阿拉伯史料。内容涵盖军事、社会与宗教政策，强调‘公正’与‘忠诚’，是游牧习惯法成文化的典范，深刻影响了中亚政治哲学。"},
    {title: "《彰所知论》", author: "八思巴", era: "1278年", desc: "八思巴为元朝太子真金所撰的佛教哲学概论，将藏传佛教的宇宙论、因果论与蒙古传统信仰结合，是蒙古佛教哲学的早期系统著作，也体现了政教合一的思想。"},
    {title: "《蒙古源流》", author: "萨冈彻辰", era: "1662年", desc: "蒙古历史哲学里程碑，以佛教转轮王观念重构从成吉思汗到清初的蒙古历史，强调因果报应与佛法护国，是蒙古佛教化历史观的集大成者。"},
    {title: "《智慧集》（Diwan-i Hikmat）", author: "阿合马·叶塞维", era: "12世纪", desc: "中亚苏菲主义经典，以突厥语诗歌形式表达神秘主义哲学，强调对真主的爱、简朴生活与导师指引，对游牧民族的伊斯兰化产生了深远影响。"},
    {title: "《美德城邦居民意见书》", author: "法拉比", era: "10世纪", desc: "中亚出生的哲学家法拉比的代表作，融合柏拉图《理想国》与伊斯兰教义，提出理想城邦基于智慧与正义，是伊斯兰政治哲学的奠基之作。"},
    {title: "《治疗论》", author: "伊本·西那", era: "11世纪", desc: "伊本·西那的哲学百科全书，涵盖逻辑、自然哲学、形而上学与伦理学，其中‘存在本质’的讨论对中亚伊斯兰哲学产生决定性影响。"},
    {title: "《纳格什班迪语录》", author: "纳格什班德及弟子", era: "14世纪", desc: "纳格什班迪教团的核心文献，记录‘沉默的记念’（dhikr khafi）等修行方法，强调入世修行与精神导师制，是中亚苏菲哲学的重要文本。"},
    {title: "《游牧文明论》", author: "仁钦·乔玛", era: "1990年", desc: "当代蒙古哲学家代表作，系统论述游牧文明的哲学基础、生态智慧与现代意义，试图将传统腾格里思想与全球生态危机对话。"},
    {title: "《草原与城市》", author: "奥莉加·苏莱曼诺娃", era: "2005年", desc: "哈萨克斯坦哲学家的跨文化研究，探讨游牧传统与现代城市化之间的张力，提出‘欧亚主义’框架下的中亚哲学新路径。"},
  ],
